import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";

const CreatePlan = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    patientName: "",
    symptoms: "",
    goal: "",
    preference: "",
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post(
        "http://localhost:5000/api/dietplan/create",
        formData,
        {
          headers: {
            Authorization: "Bearer " + localStorage.getItem("token"),
          },
        }
      );

      console.log("✅ Plan created:", res.data);
      navigate("/meal-plan");
    } catch (err) {
      console.log("🔥 FULL ERROR:", err.response?.data || err);
      alert(
        "❌ " +
          (err.response?.data?.error ||
            "Error creating plan. Check backend & AI service.")
      );
    }
  };

  return (
    <div className="container my-5">
      <h2 className="mb-4">Create Your AI Powered Meal Plan</h2>
      <form onSubmit={handleSubmit}>
        {/* Patient Name */}
        <div className="mb-3">
          <label className="form-label">Patient Name</label>
          <input
            type="text"
            className="form-control"
            name="patientName"
            value={formData.patientName}
            onChange={handleChange}
            required
          />
        </div>

        {/* Symptoms */}
        <div className="mb-3">
          <label className="form-label">Symptoms</label>
          <input
            type="text"
            className="form-control"
            name="symptoms"
            value={formData.symptoms}
            onChange={handleChange}
            placeholder="e.g., fever, cough, headache"
            required
          />
        </div>

        {/* Goal */}
        <div className="mb-3">
          <label className="form-label">Health Goal</label>
          <select
            className="form-select"
            name="goal"
            value={formData.goal}
            onChange={handleChange}
            required
          >
            <option value="">Select Goal</option>
            <option value="weight-loss">Weight Loss</option>
            <option value="weight-gain">Weight Gain</option>
            <option value="diabetic-friendly">Diabetic Friendly</option>
            <option value="heart-healthy">Heart Healthy</option>
          </select>
        </div>

        {/* Preference */}
        <div className="mb-3">
          <label className="form-label">Dietary Preference</label>
          <input
            type="text"
            className="form-control"
            name="preference"
            value={formData.preference}
            onChange={handleChange}
            placeholder="e.g., Vegetarian, Gluten-free"
          />
        </div>

        <button type="submit" className="btn btn-primary w-100">
          Generate AI Meal Plan
        </button>
      </form>
    </div>
  );
};

export default CreatePlan;
